static boolean preserveWhitespace(Node node) {
    return preserveWhitespace(node, 0);
}

private static boolean preserveWhitespace(Node node, int depth) {
    // looks only at this element and five levels up, to prevent recursion & needless stack searches
    if (node != null && node instanceof Element && depth < 6) { // depth < 6 means 0-5 (six levels: current element + 5 up)
        Element el = (Element) node;
        if (el.tag.preserveWhitespace())
            return true;
        else
            return preserveWhitespace(el.parent(), depth + 1);
    }
    return false;
}

